use std::process::Command;
use std::path::Path;

fn convert_file(filename: &str, target_format: &str) -> Result<String, Box<dyn std::error::Error>> {
    let input_path = Path::new(filename);
    let output_filename = format!("{}.{}", 
        input_path.file_stem().unwrap().to_str().unwrap(), 
        target_format
    );
    
    let output_path = input_path.parent().unwrap().join(&output_filename);
    
    let output_str = output_path.to_str().unwrap();
    
    let status = match target_format {
        "pdf" => Command::new("libreoffice")
            .arg("--headless")
            .arg("--convert-to")
            .arg("pdf")
            .arg(filename)
            .arg("--outdir")
            .arg(input_path.parent().unwrap().to_str().unwrap())
            .status()?,
        "jpg" | "jpeg" => Command::new("convert")
            .arg(filename)
            .arg(output_str)
            .status()?,
        _ => Command::new("ffmpeg")
            .arg("-i")
            .arg(filename)
            .arg("-y")
            .arg(output_str)
            .status()?,
    };
    
    if status.success() {
        Ok(output_str.to_string())
    } else {
        Err("Conversion failed".into())
    }
}